# অন্তৰদশাৰ ফলাফলৰ বাবে সৰু JSON ডাটা ফাইল
# আপুনি ইয়াত আপোনাৰ সম্পূৰ্ণ JSON ডাটা past কৰিব পাৰে
# Format: গ্ৰহ -> ৰাশি -> houses -> ঘৰ নং -> ফলাফল

import re

_CITE_RE = re.compile(r"\s*\[cite:[^\]]*\]")

def _strip_citations(text: str) -> str:
  if not text:
    return text
  return _CITE_RE.sub('', text)

