# ─── Lookup function for antardasha phala ───


def get_antardasha_phala(graha_name: str, rashi_name: str, house_num: int) -> str:
    """
    Get antardasha phala text for a given graha, rashi, and house.
    Handles both rashi-based (graha -> rashi -> houses) and direct (graha -> houses) structures.
    Returns empty string if not found.
    """
    graha_data = ANTARDASHA_PHALA_DATA.get(graha_name, {})
    if not graha_data:
      return ""

    # Check if this graha has "direct" type (no rashi nesting)
    if graha_data.get("type") == "direct":
      houses = graha_data.get("houses", {})
      ph = houses.get(str(house_num), "")
      return _strip_citations(ph)

    # Rashi-based lookup
    rashi_data = graha_data.get(rashi_name, {})
    if not rashi_data:
      return ""
    houses = rashi_data.get("houses", {})
    ph = houses.get(str(house_num), "")
    return _strip_citations(ph)


# ─── Generate all antardasha phala for PDF ───
def get_all_antardasha_phala_for_pdf() -> list:
    """
    Generate a list of all antardasha phala entries for PDF rendering.
    Returns list of dicts with: graha, rashi, house, phala_text
    """
    results = []
    for graha_name, graha_data in ANTARDASHA_PHALA_DATA.items():
      if graha_data.get("type") == "direct":
        # Direct type: no rashi nesting
        houses = graha_data.get("houses", {})
        for house_num, phala_text in houses.items():
          results.append({
            "graha": graha_name,
            "rashi": "সকলো ৰাশি",
            "house": house_num,
            "phala": _strip_citations(phala_text)
          })
      else:
        # Rashi-based
        for rashi_name, rashi_data in graha_data.items():
          if rashi_name == "type":
            continue
          houses = rashi_data.get("houses", {})
          for house_num, phala_text in houses.items():
            results.append({
              "graha": graha_name,
              "rashi": rashi_name,
              "house": house_num,
              "phala": _strip_citations(phala_text)
            })
    return results
